package ru.memearena.tournament.infrastructure; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.tournament.domain.*; import java.util.*; public interface TournamentEntryRepository extends JpaRepository<TournamentEntry,UUID>{ List<TournamentEntry> findByTournamentIdOrderBySeed(UUID id); Optional<TournamentEntry> findByTournamentIdAndMemeId(UUID t,UUID m); @Query("select e.memeId from TournamentEntry e where e.tournamentId=:t") Set<UUID> memeIds(@Param("t") UUID t); }
